  const handleLogin = async (e: FormEvent) => {
    e.preventDefault();
    setLoginError("");

    const rawUsername = loginForm.username.trim();
    const lowerUsername = rawUsername.toLowerCase();
    const isStaffOrAdmin = lowerUsername.endsWith("@fit.com") || 
                           lowerUsername === "admin" || 
                           lowerUsername === "staff" || 
                           lowerUsername === "pt";

    if (!isStaffOrAdmin) {
      // Must be a member login: only phone number with exactly 10 digits
      const isDigitOnly = /^\d+$/.test(rawUsername);
      if (!isDigitOnly || rawUsername.length !== 10) {
        setLoginError("Hội viên đăng nhập bắt buộc chỉ sử dụng số điện thoại gồm đúng 10 chữ số.");
        addNotification("Hội viên đăng nhập bắt buộc chỉ sử dụng số điện thoại gồm đúng 10 chữ số.", "error");
        return;
      }
    }

    if (isNewMemberOtpFlow) {
      if (!otpSent || !otpCode) {
        setLoginError("Vui lòng kích hoạt 'GỬI MÃ OTP' trước khi xác nhận.");
        addNotification("Vui lòng kích hoạt 'GỬI MÃ OTP' trước khi xác nhận.", "error");
        return;
      }
      if (customOtpInput.trim() !== otpCode) {
        setLoginError("Mã xác thực OTP nhập vào không chính xác.");
        addNotification("Mã xác thực OTP nhập vào không chính xác.", "error");
        return;
      }

      setIsLoggingIn(true);
      try {
        const otpPayload = {
          phone: rawUsername,
          fullName: otpFullName,
          otp: customOtpInput.trim()
        };
        const res = await fetch("/api/login-otp", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(otpPayload),
        });
        if (res.ok) {
          const userData = await res.json();
          setUser(userData);
          addNotification(`Đăng nhập OTP thành công! Chào mừng ${userData.fullName}!`, "success");
        } else {
          const error = await res.json();
          setLoginError(error.message || "Đăng nhập OTP thất bại");
          addNotification(error.message || "Đăng nhập OTP thất bại", "error");
        }
      } catch (error) {
        setLoginError(t('connectionError'));
      } finally {
        setIsLoggingIn(false);
      }
      return;
    }

    setIsLoggingIn(true);
    try {
      const loginPayload = {
        username: rawUsername,
        password: loginForm.password.trim()
      };
      const res = await fetch("/api/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(loginPayload),
      });
      if (res.ok) {
        const userData = await res.json();
        setUser(userData);
        addNotification(`${t('welcomeBack')}, ${userData.fullName}!`, "success");
      } else {
        const error = await res.json();
        setLoginError(error.message || t('wrongCredentials'));
        addNotification(t('loginFailed'), "error");
      }
    } catch (error) {
      setLoginError(t('connectionError'));
    } finally {
      setIsLoggingIn(false);
    }
  };

